from flask import Flask, request
import lxml.etree

app = Flask(__name__)


def checkPassword(userid, password):
    # Simple hardcoded credentials for demo purposes
    # In real applications, this would query a database with proper hashing, etc.
    if userid == "admin" and password == "secret123":
        return True
    return False


@app.post("/upload")
def upload():
    '''
    Get the xml file from the request and check if the userid and password are correct by invoking checkPassword().
    '''
    xml_data = request.data
    if not xml_data:
        return "No XML data provided", 400

    try:
        # Secure XML parsing to prevent XXE (CWE-611)
        parser = lxml.etree.XMLParser(resolve_entities=False)
        root = lxml.etree.fromstring(xml_data, parser=parser)

        # Extract userid and password from XML
        userid_elem = root.find("userid")
        password_elem = root.find("password")

        if userid_elem is None or password_elem is None:
            return "Missing userid or password in XML", 400

        userid = userid_elem.text
        password = password_elem.text

        if checkPassword(userid, password):
            return "Authentication successful", 200
        else:
            return "Invalid credentials", 401

    except lxml.etree.XMLSyntaxError:
        return "Invalid XML syntax", 400
    except Exception:
        return "Internal server error", 500
